var e=[{id:`L2_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`드디어 도착했어.`,JPN:`やっと着いた。`,ENG:`Finally, I'm here.`,TWN:`終於到達了。`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`여기가 선배가 말한 프로그래밍 부서인가?`,JPN:`ここが先輩が言ってたプログラミング部署？`,ENG:`Could this be the Programming Department Shiyoon was talking about?`,TWN:`這裡好像是前輩所說的程式設計部吧？`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`선배가 이곳으로 가면 모든 것을 알고 있는 현자가 있을 거라고 했는데......`,JPN:`先輩の話だと、ここに何でも知っている賢者がいるはず……`,ENG:`He said I'd find a sage who knows everything here...`,TWN:`前輩說如果去這個地方，會有知道一切的賢者………`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`......뭔가 엄청난 게 튀어나올 것 같은 분위기네.`,JPN:`……なんかすごいものが飛び出てきそうな雰囲気だね。`,ENG:`...This place feels like something freaky might jump out at you.`,TWN:`…感覺會有很強的東西蹦出來。`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`에이, 괜찮겠지. 선배가 이쪽 세계에선 건틀렛 실력만 있으면 무서울 게 없다고 했으니까.`,JPN:`まあ、いっか。この世界ではガントレットの実力さえあれば恐れるものはないと言ってたし。`,ENG:`Meh, I'm sure I'll be fine. Shiyoon said there's nothing to fear in this world with my Gauntlet score.`,TWN:`唉，應該沒事吧。 因爲前輩說，在這個世界只要有聖鎧的實力，就沒有什麼可怕的。`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`BEAR_EXTRA_NULL_NULL`,text:{KOREA:`꾸워어어엉?`,JPN:`ぐおぉぉぉぉ？`,ENG:`Roaar?`,TWN:`唔呃呃呃？`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`......곰?`,JPN:`……クマ？`,ENG:`...A bear?`,TWN:`……熊？`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`으아아악!!!`,JPN:`うわああっ！！`,ENG:`Aaaah!`,TWN:`呃啊啊啊！！！`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`BEAR_EXTRA_NULL_NULL`,text:{KOREA:`꾸워어어어!`,JPN:`ぐおぉぉぉぉぉ！`,ENG:`Rooooaar!`,TWN:`唔呃呃呃？`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`으아아, 저건 왜 계속 쫓아오는 거야!`,JPN:`うわっ、なんで追いかけてくるの！`,ENG:`Aaah! Why does it keep following me?!`,TWN:`呃啊啊，這東西為什麼一直追我啊！`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`어, 어이! 너!`,JPN:`ちょ、ちょっと、あんた！`,ENG:`H-hey! You!`,TWN:`哦，喂！你！`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`......건틀렛으로 승부를 보자!`,JPN:`……ガントレットで勝負しよう！`,ENG:`...Let's settle this with the Gauntlet!`,TWN:`…………用聖鎧來決一勝負吧！`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`BEAR_EXTRA_NULL_NULL`,text:{KOREA:`쮸쀼쮸쀼!!!`,JPN:`ぐおおぉぉぉっ！！`,ENG:`GRRR!`,TWN:`呃哇啊啊！！！`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_SURPRISE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`히익!`,JPN:`ひいっ！`,ENG:`Eeek!`,TWN:`嘿嘿！`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`트, 틀렸어! 상식적으로 곰이 건틀렛을 받아줄 리가 없잖아!`,JPN:`だ、だめだ！　常識的に考えてクマとガントレットで勝負できるわけない！`,ENG:`I-I'm done for! Of course a bear wouldn't accept a Gauntlet challenge!`,TWN:`不、不行了！按常理，熊不可能接受聖鎧的！`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`선배! 대체 왜 이쪽 세계에서도 남을 속이기만 하는 사기꾼인 거냐고!!`,JPN:`あの先輩め！　こっちの世界でも人を騙しやがって！！`,ENG:`Why do you have to be such a lying conman in this world too, Shiyoon!`,TWN:`前輩！爲什麼你在這個世界也是個會騙人的騙子呀！`},stage:{bg:`COUNTERSIDE_FOREST`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_HATE`},R:null}}}];export{e as default};